*_record_hunting_three_loads

; 記録
[if exp='game.hyperBombsCount == 0 && ! game.map.events.has(3) && ! game.map.events.has(4) && ! game.map.events.has(5)']
	@eval exp='sf.huntedThreeLordsWithoutHyperBombs = true'
[endif]

[eventoff]
;-------------------------------------------------------------------------------
*event_6
;[exp] onObjectTrigger

@delevent
@se f=kacha
@wait time=800
@se f=fence
@switchfence x=33 y=33 way=e mode=open
@notice text="I heard a door open somewhere!"

[eventoff]
;-------------------------------------------------------------------------------
*event_7
;[exp] party.lastIsMove

[texton]
[name n=Devil f=imp_00]「Hey, how did humans manage to come this far? How strong are you guys?」[k]
[name n=Devil f=imp_00]「Well, even you guys can't beat the Three Great Demon Lords! The Demon Lords are seriously powerful!」[k]
[name n=Devil f=imp_00]「If you ever encounter the Demon Lords, you'd better run away immediately!」[k]
[textoff]

[eventoff]
;-------------------------------------------------------------------------------
*event_8
;[exp] party.lastIsMove

[texton]
[name n=Devil f=succubus_10]「The Demon Lords are strong, but there's a dragon that's even stronger sleeping on the floor below.」[k]
[name n=Devil f=succubus_10]「If you don't want to die, don't go near that dragon!」[k]
[textoff]

[eventoff]
;-------------------------------------------------------------------------------
*event_9
;[exp] party.lastIsMove

[texton]
[name n=Woman f=bladesman_silver_03]「Thank you for helping me. I am an adventurer like you. My party got carried away and we ended up here, but we lost against the demons.」[k]
[name n=Woman f=bladesman_silver_03]「Everyone else in the party was killed, But I was captured and kept alive for the demons' sexual gratification.」[k]
[name n=Woman f=bladesman_silver_03]「This is a terrifying place. There are many terrifying demons here that you have never seen on the surface. You should run away quickly.」[k]
[textoff]
@changefloor pimg=void
@delevent

[eventoff]
;-------------------------------------------------------------------------------
*event_10
;[exp] party.lastIsMove

[texton]
[name n=Girl f=priest_pink_03]「Thank you for helping me... I was kidnapped by a demon who came to the human world and brought here...」[k]
[name n=Girl f=priest_pink_03]「I've been forced to be the sexual partner of demons here for so long... Now I am finally free from them. Thank you so much.」[k]
[textoff]
@changefloor pimg=void
@delevent

[eventoff]
